// Shared icon entry wrapper for Pinankou
@Component
export struct SvgIcon {
  @Prop iconSize: number = 24;
  @Prop color: string = '#111827';
  @Prop strokeWidth: number = 2;
  @Prop variant: string = 'home';

  build() {
    Image($rawfile(this.fileNameForVariant()))
      .width(this.iconSize)
      .height(this.iconSize)
      .objectFit(ImageFit.Contain)
      .draggable(false)
  }

  private fileNameForVariant(): string {
    const v: string = this.variant;
    if (v === 'home') {
      return 'icon_home.svg';
    } else if (v === 'inspection') {
      return 'icon_inspection.svg';
    } else if (v === 'risk') {
      return 'icon_risk.svg';
    } else if (v === 'emergency') {
      return 'icon_emergency.svg';
    } else if (v === 'profile') {
      return 'icon_profile.svg';
    } else if (v === 'add' || v === 'plus') {
      return 'icon_add.svg';
    } else if (v === 'back') {
      return 'icon_back.svg';
    } else if (v === 'search') {
      return 'icon_search.svg';
    } else if (v === 'phone' || v === 'call') {
      return 'icon_phone.svg';
    } else if (v === 'more' || v === 'chevronRight' || v === 'arrowRight') {
      return 'icon_chevron_right.svg';
    } else if (v === 'calendar') {
      return 'icon_calendar.svg';
    } else if (v === 'camera') {
      return 'icon_camera.svg';
    } else if (v === 'check' || v === 'pass') {
      return 'icon_check.svg';
    } else if (v === 'close' || v === 'fail' || v === 'x') {
      return 'icon_close.svg';
    } else if (v === 'warning') {
      return 'icon_warning.svg';
    } else if (v === 'settings') {
      return 'icon_settings.svg';
    } else if (v === 'export') {
      return 'icon_export.svg';
    }
    return 'icon_home.svg';
  }
}

