import { Theme } from '../common/Theme';
import { HomeStats, Activity } from '../models/Models';
import { Formatters } from '../common/Formatters';
import { SvgIcon } from '../common/SvgIcon';

@Component
export struct HomePage {
  @Prop stats: HomeStats = new HomeStats();
  @Prop activities: Activity[] = [];
  onReportRisk: () => void = () => {};
  onNavigateInspection: () => void = () => {};
  onNavigateEmergency: () => void = () => {};

  build() {
    Scroll() {
      Column({ space: 16 }) {
        Text('平安扣')
          .id('home-header-title')
          .fontSize(24)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.textPrimary)
          .width('100%')
          .padding({ top: 8, bottom: 8 })

        Row({ space: 12 }) {
          this.StatCard('今日巡检', this.stats.todayInspectionCount, 'home-stat-today-inspection')
          this.StatCard('待处理隐患', this.stats.pendingRiskCount, 'home-stat-pending-risk')
        }
        .width('100%')
        .justifyContent(FlexAlign.SpaceBetween)

        Row({ space: 12 }) {
          this.StatCard('逾期风险', this.stats.overdueRiskCount, 'home-stat-overdue-risk')
          this.StatCard('整改率', this.stats.closedRate, 'home-stat-closed-rate')
        }
        .width('100%')
        .justifyContent(FlexAlign.SpaceBetween)

        Row({ space: 12 }) {
          this.QuickAction('上报隐患', 'risk', () => this.onReportRisk(), 'home-quick-action-report')
          this.QuickAction('去巡检', 'inspection', () => this.onNavigateInspection(), 'home-quick-action-inspection')
          this.QuickAction('应急联系', 'emergency', () => this.onNavigateEmergency(), 'home-quick-action-contact')
        }
        .width('100%')

        Column({ space: 8 }) {
          Text('隐患状态分布')
            .fontSize(16)
            .fontWeight(FontWeight.Medium)
            .fontColor(Theme.textPrimary)
            .width('100%')

          this.RiskDistribution()
        }
        .id('home-chart-risk-distribution')
        .width('100%')
        .padding(16)
        .backgroundColor(Theme.cardBg)
        .borderRadius(Theme.radiusCard)

        Column({ space: 8 }) {
          Text('最近动态')
            .fontSize(16)
            .fontWeight(FontWeight.Medium)
            .fontColor(Theme.textPrimary)
            .width('100%')

          if (this.activities.length === 0) {
            EmptyStateView({ message: '暂无动态', id: 'home-empty-activity' })
          } else {
            ForEach(this.activities, (activity: Activity) => {
              Row({ space: 12 }) {
                Column() {
                  Text(activity.title)
                    .fontSize(14)
                    .fontColor(Theme.textPrimary)
                    .maxLines(1)
                    .textOverflow({ overflow: TextOverflow.Ellipsis })
                }
                .layoutWeight(1)
                .alignItems(HorizontalAlign.Start)

                Text(Formatters.dateTimeString(activity.timestamp))
                  .fontSize(12)
                  .fontColor(Theme.textTertiary)
              }
              .width('100%')
              .padding({ top: 12, bottom: 12 })
              .border({ width: { bottom: 1 }, color: Theme.borderSoft })
            }, (activity: Activity) => activity.id)
          }
        }
        .id('home-recent-activity-list')
        .width('100%')
        .padding(16)
        .backgroundColor(Theme.cardBg)
        .borderRadius(Theme.radiusCard)
      }
      .width('100%')
      .padding(Theme.pageHorizontalPadding)
      .alignItems(HorizontalAlign.Start)
    }
    .width('100%')
    .height('100%')
    .backgroundColor(Theme.pageBg)
  }

  @Builder
  StatCard(label: string, value: string | number, componentId: string) {
    Column({ space: 4 }) {
      Text(String(value))
        .id(componentId)
        .fontSize(28)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.brandPrimary)
      Text(label)
        .fontSize(13)
        .fontColor(Theme.textSecondary)
    }
    .width('48%')
    .padding(16)
    .backgroundColor(Theme.cardBg)
    .borderRadius(Theme.radiusCard)
    .alignItems(HorizontalAlign.Start)
  }

  @Builder
  QuickAction(label: string, icon: string, onTap: () => void, componentId: string) {
    Column({ space: 6 }) {
