export class Theme {
  static readonly pageBg: string = '#F0F7F6';
  static readonly cardBg: string = '#FFFFFF';
  static readonly brandPrimary: string = '#0D9488';
  static readonly brandDark: string = '#0F5C55';
  static readonly brandLight: string = '#CCFBF1';
  static readonly safeBlue: string = '#0EA5E9';
  static readonly warnOrange: string = '#F59E0B';
  static readonly dangerRed: string = '#EF4444';
  static readonly criticalPurple: string = '#8B5CF6';

  static readonly textPrimary: string = '#111827';
  static readonly textSecondary: string = '#4B5563';
  static readonly textTertiary: string = '#9CA3AF';
  static readonly textQuaternary: string = '#9CA3AF';
  static readonly textPlaceholder: string = '#9CA3AF';
  static readonly borderDefault: string = '#E5E7EB';
  static readonly borderSoft: string = 'rgba(0,0,0,0.06)';
  static readonly cardDivider: string = '#F3F4F6';
  static readonly chipSelectedStart: string = '#CCFBF1';
  static readonly chipSelectedEnd: string = '#99F6E4';
  static readonly chipSoftBg: string = '#F0F7F6';
  static readonly goldSoftBg: string = '#FEF9C3';
  static readonly softHoverBg: string = '#F3F4F6';

  static readonly radiusChip: number = 20;
  static readonly radiusCard: number = 16;
  static readonly radiusHero: number = 20;
  static readonly radiusButton: number = 24;
  static readonly radiusSmall: number = 12;
  static readonly radiusTiny: number = 8;
  static readonly radiusPill: number = 999;

  static readonly pageHorizontalPadding: number = 16;
  static readonly bottomTabHeight: number = 68;
  static readonly contentMaxWidth: number = 420;
  static readonly touchTarget: number = 44;
}

export class BrandGradient {
  static readonly primary: LinearGradient = {
    angle: 135,
    direction: GradientDirection.RightTop,
    colors: [['#0D9488', 0.0], ['#0F5C55', 1.0]]
  } as LinearGradient;

  static readonly chipSelected: LinearGradient = {
    angle: 135,
    direction: GradientDirection.RightTop,
    colors: [['#CCFBF1', 0.0], ['#99F6E4', 1.0]]
  } as LinearGradient;
}

import { Theme } from '../common/Theme';
import { HomeStats, Activity } from '../models/Models';
import { Formatters } from '../common/Formatters';
import { SvgIcon } from '../common/SvgIcon';

@Component
export struct HomePage {
  @Prop stats: HomeStats = new HomeStats();
  @Prop activities: Activity[] = [];
  onReportRisk: () => void = () => {};
  onNavigateInspection: () => void = () => {};
  onNavigateEmergency: () => void = () => {};

  build() {
    Scroll() {
      Column({ space: 16 }) {
        Row() {
          Text('平安扣')
            .id('home-header-title')
            .fontSize(24)
            .fontWeight(FontWeight.Bold)
            .fontColor(Theme.textPrimary)
            .letterSpacing(-0.3)
          Blank()
          Image($rawfile('icon_settings.svg'))
            .width(20)
            .height(20)
            .fillColor(Theme.textPrimary)
        }
        .width('100%')
        .padding({ top: 8, bottom: 8 })

        Row() {
          Column({ space: 6 }) {
            Text('今日安全，由我守护')
              .fontSize(20)
              .fontWeight(FontWeight.Bold)
              .fontColor('#FFFFFF')
            Text('完成巡检 · 闭环隐患 · 守护现场')
              .fontSize(14)
              .fontColor('rgba(255,255,255,0.92)')
          }
          .layoutWeight(1)
          .alignItems(HorizontalAlign.Start)

          Image($rawfile('icon_shield.svg'))
            .width(48)
            .height(48)
        }
        .width('100%')
        .padding(22)
        .backgroundImage({
          src: '',
          colors: [['#0D9488', 0.0], ['#2DD4BF', 1.0]]
        } as LinearGradient)
        .backgroundColor(Theme.brandPrimary)
        .borderRadius(Theme.radiusHero)

        Row({ space: 12 }) {
          this.StatCard('今日巡检', this.stats.todayInspectionCount, 'home-stat-today-inspection', 'icon_check')
          this.StatCard('待处理隐患', this.stats.pendingRiskCount, 'home-stat-pending-risk', 'icon_risk')
        }
        .width('100%')
        .justifyContent(FlexAlign.SpaceBetween)

        Row({ space: 12 }) {
          this.StatCard('逾期风险', this.stats.overdueRiskCount, 'home-stat-overdue-risk', 'icon_warning')
          this.StatCard('整改闭环率', this.stats.closedRate, 'home-stat-closed-rate', 'icon_check')
        }
        .width('100%')
        .justifyContent(FlexAlign.SpaceBetween)

        Column({ space: 12 }) {
          Text('快捷入口')
            .fontSize(18)
            .fontWeight(FontWeight.Bold)
            .fontColor(Theme.textPrimary)
            .width('100%')

          Row({ space: 12 }) {
            this.QuickAction('上报隐患', 'add', 'home-quick-action-report', Theme.brandPrimary, '#FFFFFF', () => this.onReportRisk())
            this.QuickAction('开始巡检', 'inspection', 'home-quick-action-inspection', Theme.brandLight, Theme.brandPrimary, () => this.onNavigateInspection())
            this.QuickAction('应急联系', 'emergency', 'home-quick-action-contact', '#FFEDD5', '#D97706', () => this.onNavigateEmergency())
            this.QuickAction('统计报表', 'more', '', '#E0F2FE', '#0EA5E9', () => {})
          }
          .width('100%')
        }
        .width('100%')

        Column({ space: 12 }) {
          Row() {
            Text('隐患状态分布')
              .fontSize(16)
              .fontWeight(FontWeight.Bold)
              .fontColor(Theme.textPrimary)
            Blank()
            Row({ space: 8 }) {
              this.Legend('待整改', '#0D9488')
              this.Legend('整改中', '#0EA5E9')
              this.Legend('待复核', '#D97706')
              this.Legend('已关闭', '#16A34A')
            }
          }
          .width('100%')

          this.RiskDistribution()
        }
        .id('home-chart-risk-distribution')
        .width('100%')
        .padding(16)
        .backgroundColor(Theme.cardBg)
        .borderRadius(Theme.radiusCard)

        Column({ space: 12 }) {
          Text('最近动态')
            .fontSize(18)
            .fontWeight(FontWeight.Bold)
            .fontColor(Theme.textPrimary)
            .width('100%')

          Column() {
            if (this.activities.length === 0) {
              EmptyStateView({ message: '暂无动态', id: 'home-empty-activity' })
            } else {
              ForEach(this.activities, (activity: Activity) => {
                Row({ space: 12 }) {
                  Circle({ width: 8, height: 8 })
                    .fill(this.activityColor(activity.type))
                    .margin({ top: 6 })

                  Column({ space: 2 }) {
                    Text(activity.title)
                      .fontSize(14)
                      .fontWeight(FontWeight.Medium)
                      .fontColor(Theme.textPrimary)
                      .maxLines(1)
                      .textOverflow({ overflow: TextOverflow.Ellipsis })
                    Text(Formatters.dateTimeString(activity.timestamp))
                      .fontSize(12)
                      .fontColor(Theme.textSecondary)
                  }
                  .layoutWeight(1)
                  .alignItems(HorizontalAlign.Start)
                }
                .id(`home-activity-${activity.id}`)
                .width('100%')
                .padding({ top: 12, bottom: 12 })
                .border({ width: { bottom: 1 }, color: Theme.borderSoft })
              }, (activity: Activity) => activity.id)
            }
          }
          .id('home-recent-activity-list')
          .width('100%')
          .padding(16)
          .backgroundColor(Theme.cardBg)
          .borderRadius(Theme.radiusCard)
        }
        .width('100%')
      }
      .width('100%')
      .padding(Theme.pageHorizontalPadding)
      .padding({ bottom: 100 })
      .alignItems(HorizontalAlign.Start)
    }
    .width('100%')
    .height('100%')
    .backgroundColor(Theme.pageBg)
  }

  @Builder
  StatCard(label: string, value: string | number, componentId: string, icon: string) {
    Column({ space: 4 }) {
      SvgIcon({ variant: icon, iconSize: 28, color: Theme.brandPrimary })
      Text(label)
        .fontSize(12)
        .fontColor(Theme.textSecondary)
      Text(String(value))
        .id(componentId)
        .fontSize(28)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.textPrimary)
        .letterSpacing(-0.5)
    }
